import{_ as e,o as t,c as p,j as r,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"鬼妖村正","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/鬼妖村正.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/鬼妖村正.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/鬼妖村正.md"};function d(_,a,b,l,i,c){return t(),p("div",null,[...a[0]||(a[0]=[r("h1",{id:"鬼妖村正",tabindex:"-1"},[s("鬼妖村正 "),r("a",{class:"header-anchor",href:"#鬼妖村正","aria-label":'Permalink to "鬼妖村正"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),n('<h1 id="鬼妖村正-1" tabindex="-1">鬼妖村正 <a class="header-anchor" href="#鬼妖村正-1" aria-label="Permalink to &quot;鬼妖村正&quot;">​</a></h1><p>鬼妖村正<br> C+2500<br> 这是一把红色刀刃，黑色刀柄与刀鞘，刀身上闪烁着电光的高频武士刀，即使是最强大的怪物也能干净利落地切碎。<br> 但此刻，鬼妖村正的力量还未被唤醒，完成试炼才能逐步解封它的力量。</p><p>现阶段，鬼妖村正的武器伤害9L，武器体积为7，这意味着使用它的触及范围也随之上升。持有鬼妖村正会让使用者的精神和身体承受负担，在此阶段下，持有鬼妖村正会占据使用者的2点意志上限和1点血量上限。<br> 使用鬼妖村正进行的攻击会以极快的速度再劈砍、上挑一次，这意味着在进行不附带任何招式的攻击时，鬼妖村正还会至多再使被攻击者承受2点多次攻击减值。同时，使用鬼妖村正进行不附带任何招式的攻击还会在每次成功命中的攻击结束时积累1点武器能量，武器能量无上限，且会在场景结束时自动清空。<br> 鬼妖村正会随着使用者完成试炼和达到条件而觉醒力量。</p><p>当使用者完成了3项试炼，且最高内在支线等级在持有鬼妖村正期间达到了B级，鬼妖村正将升至B级。<br> 鬼妖村正的武器伤害提升30L，体积提升12点<br> 同时，使用鬼妖村正时将立即额外再获得剑气波、升龙斩、下坠击三个招式。</p><p>剑气波<br> 需要1点武器能量<br> 使用者先以一个迅捷动作按下刀柄上的开关转化武器能量，并再使用一个标准动作挥刀斩击，进行一次白刃攻击检定，发射一道剑气波。<br> 这次挥砍将不会造成伤害，而是由剑气波造成伤害，这道剑气波视为具有【能量武器】、【超级贯穿】，并具有完成的试炼场数*5米射程，在成功命中且造成伤害后，使用者将立即闪身移动至其背后，其移动上限不能超过使用者单移动距离，这是一个C级创伤来源的传送效果，若命中了多个目标，则选择一个进行闪烁。</p><p>升龙斩<br> 需要1点武器能量<br> 使用者使用一个迅捷动作准备，然后使用标准动作施展升龙斩，立即向任一水平方向冲刺等同于单移动动作一半的移动距离，在触碰到第一个敌人时停止，先进行一次白刃检定，这次攻击额外附带B级击飞效果和【毁灭】，再立即进行一次跳跃检定，这次跳跃视为助跑跳，跳跃方式为跳高，取出目一半+试炼场数*5米，你因此而落地时不会受到任何坠落伤害。在这次攻击过后，你会额外获得1点仅能用于释放下坠击的武器能量。</p><p>下坠击<br> 需要升龙斩提供的1点武器能量<br> 必须在浮空时才能使用下坠击。使用者先使用一个迅捷动作准备，然后使用一个标准动作施展下坠击，立即对一个接触范围内的浮空状态的敌人进行一次白刃检定，此次白刃检定具有【9加骰】，使用强韧豁免进行对抗，同时将自身和该敌人同时坠击向地面，额外下落等同于使用者的单移动距离，若下坠击成功击中地面，则立即对该敌人造成等同于对抗差值的伤害，并对落点为圆心15米半径范围内的所有敌人造成伤害，同样使用强韧豁免进行对抗，使用者不会因此次落地而受到坠落伤害。下坠击额外附带等同于试炼场数*1点的附加成功。</p><p>次元斩<br> 需要在一场战斗中先后使用过剑气波、升龙斩、下坠击。<br> 使用次元斩时首先要使用一个迅捷动作将鬼妖村正归鞘，在那之后，使用一个标准动作对触及范围内的所有敌人进行一次白刃检定攻击，最后，使用一个移动动作引爆因快速切割而撕裂的空间。这意味着使用次元斩是一个整轮动作，攻击触及范围内的所有敌人，使用强韧豁免进行对抗，但这些伤害不会立即生效，而是在使用移动动作引爆后开始生效，无数被割裂的时空碎片飞溅，这次攻击将额外附带A级重伤和碾压效果，所有受到伤害的目标将被立即关入破碎的异空间之中，这是一个B级时空来源的放逐效果，这个效果将持续一轮。</p><p>试炼：<br> 完成一次试炼需要使用者在不使用任何其他武器的情况下，使用鬼妖村正在没有其他轮回者或NPC助力的前提下亲手击杀一名比其支线等级高1级的BOSS，并活着完成这场影片，视为完成了一次试炼。相应的，为了其他轮回者的体验，主神可以选择为鬼妖村正的持有者单独准备一个BOSS。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',11)])])}const f=e(o,[["render",d]]);export{m as __pageData,f as default};
